  1â†’/*
  2â†’ *  Create an empty Yalnix file system on the Yalnix DISK.
  3â†’ *
  4â†’ *  This is a Unix program (not a Yalnix program).  It creates a Yalnix
  5â†’ *  file system in the Unix file named "DISK".  This file is then used
  6â†’ *  by the Yalnix hardware simulation as the Yalnix disk device.  You
  7â†’ *  can write other Unix programs or use existing Unix tools to create
  8â†’ *  "interesting" DISK contents to test your server on or to examine
  9â†’ *  the "raw" contents of your file system on disk.  For example,
 10â†’ *  running "od -X DISK" or "od -c DISK" under Unix can be useful ways
 11â†’ *  to get a quick look at the DISK contents.
 12â†’ *
 13â†’ *  Usage: mkyfs [num_inodes]
 14â†’ *
 15â†’ *  The default number of inodes if num_inodes is not specified is
 16â†’ *  given by the DEFAULT_NUM_INODES constant below.
 17â†’ *
 18â†’ *  RUN THIS COMMAND AS A UNIX PROGRAM, NOT AS A YALNIX PROGRAM.
 19â†’ */
 20â†’
 21â†’#include <fcntl.h>
 22â†’#include <stdio.h>
 23â†’#include <string.h>
 24â†’#include <stdlib.h>
 25â†’#include <unistd.h>
 26â†’
 27â†’#include <comp421/filesystem.h>
 28â†’
 29â†’#define	INODES_PER_BLOCK	(BLOCKSIZE/INODESIZE)
 30â†’
 31â†’#define DISK_FILE_NAME		"DISK"
 32â†’#define DEFAULT_NUM_INODES	(6 * INODES_PER_BLOCK - 1)
 33â†’
 34â†’union {
 35â†’    struct fs_header hdr;
 36â†’    struct inode inode[INODES_PER_BLOCK];
 37â†’    char buf[BLOCKSIZE];
 38â†’} block;
 39â†’
 40â†’int
 41â†’main(int argc, char **argv)
 42â†’{
 43â†’    int disk;
 44â†’    int num_inodes = DEFAULT_NUM_INODES;
 45â†’    int i;
 46â†’    struct inode *inodes;
 47â†’    int inodes_size;
 48â†’    struct dir_entry root[2];
 49â†’
 50â†’    if (argc > 1) {
 51â†’	if (sscanf(argv[1], "%d", &num_inodes) != 1) {
 52â†’	    fprintf(stderr, "usage: mkyfs [num_inodes]\n");
 53â†’	    exit(1);
 54â†’	}
 55â†’    }
 56â†’
 57â†’    if ((disk = creat(DISK_FILE_NAME, 0666)) < 0) {
 58â†’	perror(DISK_FILE_NAME);
 59â†’	exit(1);
 60â†’    }
 61â†’
 62â†’    lseek(disk, BLOCKSIZE, 0);
 63â†’
 64â†’    inodes_size = (num_inodes + 1) * INODESIZE;
 65â†’    /* force rounded up to BLOCKSIZE multiple */
 66â†’    inodes_size = (inodes_size + BLOCKSIZE - 1) & ~(BLOCKSIZE - 1);
 67â†’    inodes = (struct inode *)malloc(inodes_size);
 68â†’
 69â†’    ((struct fs_header *)inodes)->num_blocks = NUMSECTORS;
 70â†’    ((struct fs_header *)inodes)->num_inodes = num_inodes;
 71â†’
 72â†’    inodes[1].type = INODE_DIRECTORY;
 73â†’    inodes[1].nlink = 2;
 74â†’    inodes[1].reuse = 1;
 75â†’    inodes[1].size = 2 * sizeof(struct dir_entry);
 76â†’    inodes[1].direct[0] = (inodes_size / BLOCKSIZE) + 1;
 77â†’
 78â†’    for (i = 2; i <= num_inodes; i++) {
 79â†’	inodes[i].type = INODE_FREE;
 80â†’	/* all other fields are automatically 0 */
 81â†’    }
 82â†’
 83â†’    if (write(disk, inodes, inodes_size) != inodes_size) {
 84â†’	perror("write inodes");
 85â†’	unlink(DISK_FILE_NAME);
 86â†’	exit(1);
 87â†’    }
 88â†’
 89â†’    memset((void *)root, '\0', sizeof(root));
 90â†’    root[0].inum = ROOTINODE;
 91â†’    root[0].name[0] = '.';
 92â†’    root[1].inum = ROOTINODE;
 93â†’    root[1].name[0] = '.';
 94â†’    root[1].name[1] = '.';
 95â†’
 96â†’    if (write(disk, root, sizeof(root)) != sizeof(root)) {
 97â†’	perror("write root");
 98â†’	unlink(DISK_FILE_NAME);
 99â†’	exit(1);
100â†’    }
101â†’
102â†’    /*
103â†’     *  Seek to the last block of the DISK and write it full of zeros.
104â†’     *  In Unix, this leaves a "hole" in the file, which will act
105â†’     *  exactly as if it had been written full of zeros.  When reading
106â†’     *  from this space skipped over here, Unix will read it as all
107â†’     *  zeros.  By making this a hole, it is faster to run mkyfs,
108â†’     *  and it saves real Unix disk space since a hole doesn't consume
109â†’     *  physical disk blocks.
110â†’     */
111â†’    lseek(disk, BLOCKSIZE * (NUMSECTORS - 1), 0);
112â†’    memset((void *)&block, '\0', BLOCKSIZE);
113â†’    if (write(disk, &block, BLOCKSIZE) != BLOCKSIZE) {
114â†’	perror("write last zero");
115â†’	unlink(DISK_FILE_NAME);
116â†’	exit(1);
117â†’    }
118â†’
119â†’    exit(0);
120â†’}
