 13â†’
 14â†’#include <comp421/filesystem.h>
 15â†’#include <comp421/iolib.h>
 16â†’#include <comp421/yalnix.h>
 17â†’#include <stdio.h>
 18â†’#include <stdlib.h>
 19â†’#include <string.h>
 20â†’
 21â†’#define assert(message, test) do { if (!(test)) { Shutdown(); printf(message); return 1; } } while (0)
 22â†’#define SIZE 8 * SECTORSIZE
 23â†’
 24â†’int main()
 25â†’{
 26â†’	// Set up for the tests
 27â†’	fprintf(stderr, "Set up for the read tests\n");
 28â†’
 29â†’	int fd, ret, i, j;
 30â†’	char buf[SIZE + 1], ref[SIZE], zero[SIZE], fff[SIZE];
 31â†’	struct Stat mystat;
 32â†’
 33â†’	// Fill buf with 'A' and ref with 'B'
 34â†’	for(i = 0 ; i < SIZE ; i++) {
 35â†’		buf[i] = 'A';
 36â†’		ref[i] = 'B'; // used later
 37â†’		zero[i] = '\0'; //used later
 38â†’		fff[i] = 'F'; //used later
 39â†’	}
 40â†’
 41â†’	fd = Create("a");
 42â†’
 43â†’	for(i = 0 ; i < 5 ; i++) {	// Indirect block write
 44â†’		for(j = 0 ; j < SIZE ; j++)
 45â†’			buf[j]++;
 46â†’		ret = Write(fd, buf, SIZE);
 47â†’		assert("Write position not advancing correctly in indirect block writes\n", ret == SIZE);
 48â†’	}
 49â†’
 50â†’	// Seeking to the end of those 5 blocks, skipping a block, and then writing another block
 51â†’	ret = Seek(fd, 0, SEEK_END);
 52â†’        printf("Result for Seek end: %d\n", ret);
 53â†’	assert("Seek end not working correctly\n", ret == SIZE * 5);
 54â†’
 55â†’	ret = Seek(fd, SIZE, SEEK_CUR);
 56â†’	assert("Seek not allowed to seek past end of file?\n", ret == SIZE * 6);
 57â†’
 58â†’	ret = Write(fd, buf, SIZE);
 59â†’	assert("Write position not advancing correctly after seeking past end of file\n", ret == SIZE);
 60â†’
 61â†’	ret = Seek(fd, 0, SEEK_END);
 62â†’        printf("Seek end: %d\n", ret);
 63â†’	assert("Seek set not working correctly after skipping\n", ret == SIZE * 7);
 64â†’
 65â†’	ret = Seek(fd, 0, SEEK_SET);
 66â†’	assert("Seek set not working correctly\n", ret == 0);
 67â†’
 68â†’	ret = Seek(fd, -1, SEEK_SET);
 69â†’	assert("Seek set allowed to seek before beginning of file\n", ret == ERROR);
 70â†’
 71â†’	ret = Seek(fd, -1, SEEK_CUR);
 72â†’	assert("Seek cur allowed to seek before beginning of file\n", ret == ERROR);
 73â†’	Close(fd);
 74â†’
 75â†’	// Test stat of a
 76â†’	fprintf(stderr, "Test stat of a\n");
 77â†’	ret = Stat("a", &mystat);
 78â†’	fprintf(stderr, "Stat a: [%d], inode=%d, type=%d, size=%d, nlink=%d\n", ret, mystat.inum, mystat.type, mystat.size, mystat.nlink);
 79â†’	assert("Stats failed on a", ret == 0 && mystat.inum == 47 && mystat.type == INODE_REGULAR && mystat.size == SIZE * 7 && mystat.nlink == 1);
 80â†’
 81â†’	// Begin read tests on a file
 82â†’	fprintf(stderr, "Begin read tests on a file\n");
 83â†’	fd = Open("a");
 84â†’	ret = Read(fd, buf, 16);
 85â†’	assert("Read wrong number of bytes: BBB\n", ret == 16);
 86â†’	buf[16] = 0;
 87â†’        printf("buf: %s\n", buf);
 88â†’	assert("Failed read on file: BBB\n", strncmp(buf, "BBBBBBBBBBBBBBBB", 16) == 0);
 89â†’
 90â†’	ret = Seek(fd, SIZE, SEEK_SET);
 91â†’	ret = Read(fd, buf, 16);
 92â†’	assert("Read wrong number of bytes: CCC\n", ret == 16);
 93â†’	buf[16] = 0;
 94â†’	assert("Failed read on file: CCC\n", strncmp(buf, "CCCCCCCCCCCCCCCC", 16) == 0);
 95â†’
 96â†’	ret = Seek(fd, SIZE * 2, SEEK_SET);
 97â†’	ret = Read(fd, buf, 16);
 98â†’	assert("Read wrong number of bytes: DDD\n", ret == 16);
 99â†’	buf[16] = 0;
100â†’	assert("Failed read on file: DDD\n", strncmp(buf, "DDDDDDDDDDDDDDDD", 16) == 0);
101â†’
102â†’	ret = Seek(fd, 0, SEEK_SET);
103â†’	ret = Read(fd, buf, SIZE);
104â†’	assert("Read wrong number of bytes: BBB\n", ret == SIZE);
105â†’	assert("Failed read on file: ref\n", strncmp(buf, ref, SIZE) == 0);
106â†’
107â†’	// Here we're attempting to read the '\0' gap block in the 6th block
108â†’	ret = Seek(fd, SIZE * -2, SEEK_END);
109â†’	assert("Seeking to wrong place in file: 000\n", ret == SIZE * 5);
110â†’	ret = Read(fd, buf, SIZE);
111â†’	assert("Read wrong number of bytes: 000\n", ret == SIZE);
112â†’	assert("Failed read on file: 000\n", strncmp(buf, zero, SIZE) == 0);
113â†’
114â†’	// And then we attempt to read the FFF which should be in the 7th block, right past the gap block
115â†’	ret = Read(fd, buf, SIZE);
116â†’	assert("Read wrong number of bytes: FFF\n", ret == SIZE);
117â†’	assert("Failed read on file: FFF\n", strncmp(buf, fff, SIZE) == 0);
118â†’
119â†’	ret = Seek(fd, 0, SEEK_END);
120â†’	ret = Read(fd, buf, SIZE);
121â†’	assert("Read wrong number of bytes: seek end\n", ret == 0);
122â†’	Close(fd);
123â†’
124â†’	// Test Reading and writing on directories
125â†’	fprintf(stderr, "Test Reading and writing on directories\n");
126â†’	fd = Open(".");
127â†’	ret = Read(fd, buf, 16);
128â†’	assert("Read wrong number of bytes: . dir\n", ret == 16);
129â†’	ret = Write(fd, buf, 16);
130â†’	assert("Wrote to directory\n", ret == ERROR);
131â†’	Close(fd);
132â†’
133â†’	fd = Open("/");
134â†’	ret = Read(fd, buf, 16);
135â†’	assert("Read wrong number of bytes: / dir\n", ret == 16);
136â†’	ret = Write(fd, buf, 16);
137â†’	assert("Wrote to directory\n", ret == ERROR);
138â†’	Close(fd);
139â†’
140â†’	// Null tests
141â†’	fprintf(stderr, "null tests\n");
142â†’	fd = Open(NULL);
143â†’	assert("Opened null file\n", fd == ERROR);
144â†’	ret = Read(fd, buf, 16);
145â†’	assert("Read null file\n", ret == ERROR);
146â†’	ret = Write(fd, buf, 16);
147â†’	assert("Wrote null file\n", ret == ERROR);
148â†’	ret = Stat(NULL, &mystat);
149â†’	assert("Stats on null", ret == ERROR);
150â†’	ret = Stat("a", NULL);
151â†’	assert("Stats with null stat struct", ret == ERROR);
152â†’
153â†’	// Test more stat things
154â†’	fprintf(stderr, "Test more stat things\n");
155â†’	fd = Create("b");
156â†’	for(j = 0 ; j < SIZE ; j++)
157â†’		buf[j]++;
158â†’	ret = Write(fd, buf, 16);
159â†’	Close(fd);
160â†’	ret = Stat("b", &mystat);
161â†’	assert("Stats failed on b", ret == 0 && mystat.inum == 46 && mystat.type == INODE_REGULAR && mystat.size == 16 && mystat.nlink == 1);
162â†’
163â†’	ret = MkDir("c");
164â†’	ret = Stat("c", &mystat);
165â†’	assert("Stats failed on c", ret == 0 && mystat.inum == 45 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
166â†’
167â†’	ret = MkDir("c/d");
168â†’	ret = Stat("c/d", &mystat);
169â†’	assert("Stats failed on c/d", ret == 0 && mystat.inum == 44 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
170â†’
171â†’	ret = Stat("f", &mystat);
172â†’	assert("Stats failed on f", ret == ERROR);
173â†’
174â†’	ret = Sync();
175â†’	assert("Sync failed", ret == 0);
176â†’
177â†’	printf("All tests passed\n");
178â†’	return Shutdown();
179â†’}
