 20â†’/*
 21â†’ * This test performs a series of MkDir() and ChDir() calls, and verifies that YFS
 22â†’ * is performing them as expected.
 23â†’ */
 24â†’int main()
 25â†’{
 26â†’	int ret;
 27â†’
 28â†’	// Simple MkDirs that are expected to succeed.
 29â†’	fprintf(stderr, "Simple MkDirs that are expected to succeed\n");
 30â†’	ret = MkDir("a");
 31â†’	assert("Failed simple MkDir()\n", ret == 0);
 32â†’
 33â†’	fprintf(stderr, "Simple MkDirs that are expected to succeed\n");
 34â†’	ret = MkDir("b");
 35â†’	assert("Failed simple MkDir()\n", ret == 0);
 36â†’
 37â†’	fprintf(stderr, "Simple MkDirs that are expected to succeed\n");
 38â†’	ret = MkDir("c");
 39â†’	assert("Failed simple MkDir()\n", ret == 0);
 40â†’
 41â†’	// Simple ChDir
 42â†’	fprintf(stderr, "Simple ChDir\n");
 43â†’	ret = ChDir("a");
 44â†’	assert("Failed simple ChDir()\n", ret == 0);
 45â†’
 46â†’	// More simple MkDirs and ChDirs
 47â†’	fprintf(stderr, "More simple MkDirs and ChDirs\n");
 48â†’	ret = MkDir("b");
 49â†’	assert("Failed to make a directory in a directory\n", ret == 0);
 50â†’
 51â†’	fprintf(stderr, "More simple MkDirs and ChDirs\n");
 52â†’	ret = ChDir("b");
 53â†’	assert("Failed to change to a directory once in a directory\n", ret == 0);
 54â†’
 55â†’	// One more time with simple MkDirs and ChDirs
 56â†’	fprintf(stderr, "One more time with simple MkDirs and ChDirs\n");
 57â†’	ret = MkDir("c");
 58â†’	assert("Failed to make a directory 3 deep\n", ret == 0);
 59â†’
 60â†’	fprintf(stderr, "One more time with simple MkDirs and ChDirs\n");
 61â†’	ret = ChDir("c");
 62â†’	assert("Failed to change to a directory 3 deep\n", ret == 0);
 63â†’
 64â†’	// Try ChDir up one dir
 65â†’	fprintf(stderr, "Try ChDir up one dir\n");
 66â†’	ret = ChDir("..");
 67â†’	assert("Failed to ChDir(\"..\")\n", ret == 0);
 68â†’
 69â†’	// Try ChDir same directory
 70â†’	fprintf(stderr, "Try ChDir same directory\n");
 71â†’	ret = ChDir(".");
 72â†’	assert("Failed to ChDir(\".\")\n", ret == 0);
 73â†’
 74â†’	// Try to remake the b directory, but we expect it already exists
 75â†’	fprintf(stderr, "Try to remake the b directory, but we expect it already exists\n");
 76â†’	ret = MkDir("c");
 77â†’	assert("Expected error when pathname already exists\n", ret == ERROR);
 78â†’
 79â†’	// Try an absolute ChDir
 80â†’	fprintf(stderr, "Try an absolute ChDir\n");
 81â†’	ret = ChDir("/c");
 82â†’	assert("Failed simple absolute ChDir\n", ret == 0);
 83â†’
 84â†’	// Try a root ChDir
 85â†’	fprintf(stderr, "Try a root ChDir\n");
 86â†’	ret = ChDir("/");
 87â†’	assert("Failed simple root ChDir\n", ret == 0);
 88â†’
 89â†’	// Try a complex ChDir to existing directory
 90â†’	fprintf(stderr, "Try a complex ChDir to existing directory\n");
 91â†’	ret = ChDir("/a/b/c");
 92â†’	assert("Failed complex ChDir to existing directory\n", ret == 0);
 93â†’
 94â†’	// Try a complex ChDir to a non-existent directory
 95â†’	fprintf(stderr, "Try a complex ChDir to a non-existent directory\n");
 96â†’	ret = ChDir("/a/b/c/e");
 97â†’	assert("Failed complex ChDir to non-existent directory\n", ret == ERROR);
 98â†’
 99â†’	// Try an empty pathname ChDir
100â†’	fprintf(stderr, "Try an empty pathname ChDir\n");
101â†’	ret = ChDir(NULL);
102â†’	assert("Failed empty pathname ChDir\n", ret == ERROR);
103â†’
104â†’	fprintf(stderr, "Try an empty pathname ChDir\n");
105â†’	ret = ChDir("");
106â†’	assert("Failed empty pathname ChDir\n", ret == ERROR);
107â†’
108â†’	// Try a complex ChDir to existing directory with dot at end
109â†’	fprintf(stderr, "Try a complex ChDir to existing directory with dot at end\n");
110â†’	ret = ChDir("/a/b/c/.");
111â†’	assert("Failed complex ChDir to existing directory with dot at end\n", ret == 0);
112â†’
113â†’	// Try a complex ChDir to existing relative directory
114â†’	fprintf(stderr, "Try a complex ChDir to existing relative directory\n");
115â†’	ret = ChDir("../../b/c/../../b/../../.");
116â†’	assert("Failed complex ChDir to existing relative directory\n", ret == 0);
117â†’
118â†’	printf("All tests passed\n");
119â†’	return Shutdown();
120â†’}
